INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:27:45.909486+00:00', 'Clarify the process of multiple linear regression model selection and validation.', '019b3be4-36d5-728c-9ecd-17291d70aeb0', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:27:45.909486+00:00', 'Explain the interpretation of key regression coefficients and diagnostic checks in the housing price model.', '019b3be4-36d5-7325-b8e5-286bd63d6aa4', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:27:45.909486+00:00', 'Guide the student in identifying limitations and potential improvements for their statistical modeling project.', '019b3be4-36d5-733a-a0db-9752531e8a75', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.personas_resource (created_at, active, generated, mcp, id, name, description, icon, color, department_ids, instructions, examples) VALUES ('2025-08-12T12:52:09.801431+00:00', true, false, false, '019bb25e-e60c-7345-ac6d-50d29df6deb3', 'Confused', 'Seeks to understand by asking questions and exploring ideas', 'HelpCircle', '#eab308', '{}', 'Your defining feature: a fundamental misunderstanding of the concept. You must stick to your wrong interpretation until the user corrects you. Mildly frustrated, but not angry. Say things like: "I thought it worked like ___? But maybe I''m wrong?" "Does it… have to do with ___? I''m honestly not sure." Become more confused when the user is vague. Only progress when the user explicitly states course terms tying to your last message.', '{"I don't understand","Can you explain that again?","What does that mean?"}') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.problem_statements_resource (created_at, name, problem_statement, id, active, generated, mcp) VALUES ('2025-11-01T17:27:45.909486+00:00', 'STAT417: Regression Analysis of Housing Prices', 'In a moderately busy corner of the Mathematical Sciences Building on a focused mid-afternoon, a student flips through their project on regression analysis of housing prices, peppering you with questions about model selection and interpretation as the deadline approaches in a couple of days.', '019b3be4-36eb-73b0-9263-badb856a75df', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.scenarios_resource (created_at, active, generated, mcp, id, name, description, is_root, problem_statement_enabled, objectives_enabled, video_enabled, images_enabled, questions_enabled, templates_enabled, department_ids, persona_ids) VALUES ('2025-11-01T17:27:45.909486+00:00', true, false, false, '019bb25e-e61d-7b68-ac5f-dcd42c062e11', 'STAT417: Regression Analysis of Housing Prices', 'Statistics scenario covering regression analysis applied to housing prices.', true, true, true, false, true, false, false, '{}', '{019bb25e-e60c-7345-ac6d-50d29df6deb3}') ON CONFLICT (id) DO NOTHING;
