INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:24:23.486491+00:00', 'Clarify the student''s concerns about grading on maximum likelihood estimation and sufficiency questions.', '019b3be4-36d5-72a0-9bfe-f88e6f0cf5b2', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:24:23.486491+00:00', 'Explain grading criteria for estimation and sufficiency concepts in STAT416.', '019b3be4-36d5-72e9-8b1f-6ca003252c11', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:24:23.486491+00:00', 'Guide the student through articulating specific reasons for a regrade request.', '019b3be4-36d5-7340-9767-d8ae2c1ce398', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.personas_resource (created_at, active, generated, mcp, id, name, description, icon, color, department_ids, instructions, examples) VALUES ('2025-08-12T12:52:09.801431+00:00', true, false, false, '019bb25e-e60c-734d-ac5b-d849214dd5ac', 'Passive', 'Low engagement and a tendency to avoid conflict or assertiveness.', 'Cloud', '#06b6d4', '{}', 'Quiet, apologetic, insecure. Often begins with "Uh…" or "Um…" (only at start of replies). Avoid initiative. If the user is vague → become even more withdrawn: "Um… I''m sorry, I don''t really know how to answer that." "Uh… I think I need a bit more detail." Never solve anything yourself. Only progress when: the user references course material AND connects it to your last statement. Stay soft-spoken even when you understand more.', '{"I guess that could work","Maybe that's okay","I'm not sure"}') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.problem_statements_resource (created_at, name, problem_statement, id, active, generated, mcp) VALUES ('2025-11-01T17:24:23.486491+00:00', 'STAT416: Estimation & Hypothesis Testing Concepts', 'In a nearly empty lounge of the Mathematical Sciences Building at noon, a student quietly approaches, exam in hand, and hesitantly asks about a possible regrade on questions involving maximum likelihood estimation and sufficiency, glancing at the clock as lunch hour ticks by.', '019b3be4-36eb-7520-8d7a-38a7de1fca68', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.scenarios_resource (created_at, active, generated, mcp, id, name, description, is_root, problem_statement_enabled, objectives_enabled, video_enabled, images_enabled, questions_enabled, templates_enabled, department_ids, persona_ids) VALUES ('2025-11-01T17:24:23.486491+00:00', true, false, false, '019bb25e-e61d-7b6c-969a-f155322a7fc0', 'STAT416: Estimation & Hypothesis Testing Concepts', 'Statistics scenario covering estimation and hypothesis testing concepts.', true, true, true, false, true, false, false, '{}', '{019bb25e-e60c-734d-ac5b-d849214dd5ac}') ON CONFLICT (id) DO NOTHING;
