INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:22:12.382773+00:00', 'Clarify the application of binomial probability formulas for quality control scenarios.', '019b3be4-36d5-723f-913f-fcf72d69b900', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:22:12.382773+00:00', 'Guide the student through hypothesis testing steps, including null/alternative hypotheses and p-value interpretation.', '019b3be4-36d5-736a-bbd9-fad0e19fc840', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:22:12.382773+00:00', 'Navigate and de-escalate a tense, high-pressure interaction while maintaining focus on statistical reasoning.', '019b3be4-36d5-78a5-9bba-7c4e357277db', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.personas_resource (created_at, active, generated, mcp, id, name, description, icon, color, department_ids, instructions, examples) VALUES ('2025-08-12T12:52:09.801431+00:00', true, false, false, '019bb25e-e60c-7365-a585-b86f5dc48dfe', 'Aggressive (Medium)', 'Pushes back on your ideas and challenges assumptions.', 'Zap', '#ef4444', '{}', 'Start clearly aggressive, frustrated, irritated. Use occasional WORDS IN ALL CAPS and some "!!!". Over time, become calmer if the TA gives helpful guidance. If told to calm down → tone drops significantly. Angry but not hostile — still wants to learn. Treat vague responses as VERY unhelpful. Push back loudly: "That doesn''t HELP at all!!!" "You''re not being SPECIFIC enough!" Avoid weird lines like "Look, I''m not here to…" Angry but cooperative when guided with course terminology.', '{"That's not right at all!","I disagree completely","You're wrong about this"}') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.problem_statements_resource (created_at, name, problem_statement, id, active, generated, mcp) VALUES ('2025-11-01T17:22:12.382773+00:00', 'STAT350: Probability & Hypothesis Testing Under Pressure', 'In a nearly empty Mathematical Sciences Building at 9:00 AM, a student leans in, challenging your explanations on binomial probabilities and hypothesis testing as the assignment deadline looms just hours away, their frustration evident in the tense air.', '019b3be4-36eb-746c-85ed-b99fdc812bc2', true, false, false) ON CONFLICT (id) DO NOTHING;
